161→export async function POST(request: Request): Promise<Response> {
162→  const auth = await requireUser(request);
163→  if (!auth) return errorResponse("Unauthorized", 401);
164→  const authIsAdmin = isAdminToken(auth.token);
165→  if (!authIsAdmin) return errorResponse("Forbidden", 403);
166→
167→  const url = new URL(request.url);
168→  const view = url.searchParams.get("view");
169→  if (view !== "assignments") return errorResponse("Invalid view", 400);
170→
171→  let body: CollectionAssignmentCreateInput;
172→  try {
173→    body = (await request.json()) as CollectionAssignmentCreateInput;
174→  } catch {
175→    return errorResponse("Invalid JSON body", 400);
176→  }
177→
178→  try {
179→    const created = await createAssignment(body);
180→    return jsonResponse(created, { status: 201 });
181→  } catch (error) {
182→    if (isStorageUnavailableError(error)) {
183→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
184→    }
185→    const message = error instanceof Error ? error.message : "Unable to create assignment";
186→    return errorResponse(message, 400);
187→  }
188→}
