143→export async function GET(request: Request): Promise<Response> {
144→  const auth = await requireUser(request);
145→  if (!auth) return errorResponse("Unauthorized", 401);
146→  const viewer = toSubmissionAuthContext(auth);
147→  if (!viewer) return errorResponse("Unauthorized", 401);
148→
149→  const url = new URL(request.url);
150→  const id = url.pathname.split("/").pop();
151→  const view = url.searchParams.get("view");
152→  if (!id) return errorResponse("Missing submission id", 400);
153→
154→  let events: PointEvent[];
155→  try {
156→    events = await getCombinedEvents();
157→  } catch (error) {
158→    if (isStorageUnavailableError(error)) {
159→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
160→    }
161→    throw error;
162→  }
163→
164→  if (view === "event") {
165→    const event = events.find((item) => item.id === id);
166→    if (!event) return errorResponse("Submission event not found", 404);
167→    if (!canViewEventDetail(event, viewer)) return errorResponse("Forbidden", 403);
168→    return jsonResponse(event, { status: 200 });
169→  }
170→
171→  const points = projectPointsFromEvents(events);
172→  const point = points.find((item) => item.pointId === id || item.id === id);
173→  if (point) return jsonResponse(point, { status: 200 });
174→
175→  const fallbackEvent = events.find((item) => item.id === id);
176→  if (fallbackEvent) return jsonResponse(fallbackEvent, { status: 200 });
177→
178→  return errorResponse("Submission not found", 404);
179→}
