181→export async function PUT(request: Request): Promise<Response> {
182→  const auth = await requireUser(request);
183→  if (!auth) return errorResponse("Unauthorized", 401);
184→
185→  const url = new URL(request.url);
186→  const id = url.pathname.split("/").pop();
187→  if (!id) return errorResponse("Missing submission id", 400);
188→
189→  let body: any;
190→  try {
191→    body = await request.json();
192→  } catch {
193→    return errorResponse("Invalid JSON body", 400);
194→  }
195→
196→  const details = body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : null;
197→  if (!details) return errorResponse("Missing details payload", 400);
198→
199→  try {
200→    const combinedEvents = await getCombinedEvents();
201→    const points = projectPointsFromEvents(combinedEvents);
202→    const targetPoint = points.find((point) => point.pointId === id || point.id === id);
203→    if (!targetPoint) return errorResponse("Submission not found", 404);
204→
205→    const newEvent: PointEvent = {
206→      id: crypto.randomUUID(),
207→      pointId: targetPoint.pointId,
208→      eventType: "ENRICH_EVENT",
209→      userId: auth.id,
210→      category: targetPoint.category,
211→      location: targetPoint.location,
212→      details: normalizeEnrichPayload(targetPoint.category, details),
213→      photoUrl: typeof body?.photoUrl === "string" ? body.photoUrl : undefined,
214→      createdAt: new Date().toISOString(),
215→      source: "compat_put",
216→    };
217→
218→    await insertPointEvent(newEvent);
219→    return jsonResponse(newEvent, { status: 200 });
220→  } catch (error) {
221→    if (isStorageUnavailableError(error)) {
222→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
223→    }
224→    throw error;
225→  }
226→}
