228→interface ReviewBody {
229→  decision?: unknown;
230→  notes?: unknown;
231→}
232→
233→export async function PATCH(request: Request): Promise<Response> {
234→  const auth = await requireUser(request);
235→  if (!auth) return errorResponse("Unauthorized", 401);
236→  const viewer = toSubmissionAuthContext(auth);
237→  if (!viewer) return errorResponse("Unauthorized", 401);
238→  if (!viewer.isAdmin) return errorResponse("Forbidden", 403);
239→
240→  const url = new URL(request.url);
241→  const id = url.pathname.split("/").pop();
242→  const view = url.searchParams.get("view");
243→  if (!id) return errorResponse("Missing submission id", 400);
244→  if (view !== "review") return errorResponse("Invalid view", 400);
245→
246→  let body: ReviewBody;
247→  try {
248→    body = (await request.json()) as ReviewBody;
249→  } catch {
250→    return errorResponse("Invalid JSON body", 400);
251→  }
252→
253→  const decision = normalizeReviewDecision(body.decision);
254→  if (!decision) return errorResponse("Invalid review decision", 400);
255→  const notes = trimReviewNotes(body.notes);
256→
257→  try {
258→    const updated = await applyReviewDecision({
259→      eventId: id,
260→      reviewerId: auth.id,
261→      decision,
262→      notes,
263→    });
264→    return jsonResponse(updated, { status: 200 });
265→  } catch (error) {
266→    if (isStorageUnavailableError(error)) {
267→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
268→    }
269→    const message = error instanceof Error ? error.message : "Unable to apply review decision";
270→    const status = message.includes("not found") ? 404 : 400;
271→    return errorResponse(message, status);
272→  }
273→}
