275→export async function DELETE(request: Request): Promise<Response> {
276→  const auth = await requireUser(request);
277→  if (!auth) return errorResponse("Unauthorized", 401);
278→  const viewer = toSubmissionAuthContext(auth);
279→  if (!viewer) return errorResponse("Unauthorized", 401);
280→  if (!viewer.isAdmin) return errorResponse("Forbidden", 403);
281→
282→  const url = new URL(request.url);
283→  const id = url.pathname.split("/").pop();
284→  const view = url.searchParams.get("view");
285→  if (!id) return errorResponse("Missing submission id", 400);
286→  if (view !== "event") return errorResponse("Use view=event for event deletion", 400);
287→
288→  try {
289→    const deleted = await deletePointEvent(id);
290→    if (deleted) return jsonResponse({ ok: true, id }, { status: 200 });
291→
292→    const combined = await getCombinedEvents();
293→    const existsReadOnly = combined.some((event) => event.id === id);
294→    if (existsReadOnly) {
295→      return errorResponse("Submission source is read-only and cannot be deleted", 409);
296→    }
297→    return errorResponse("Submission event not found", 404);
298→  } catch (error) {
299→    if (isStorageUnavailableError(error)) {
300→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
301→    }
302→    throw error;
303→  }
304→}
